@Slf4j
public class StandaardRekenUitArtikelAgendaService implements RekenUitArtikelAgendaService {

    @Autowired
    private OpdrachtService opdrachtService;
    @Autowired
    private ArtikelAgendaService artikelAgendaService;
    @Autowired
    private RekenmotorService vormArtikelsRekenmotorService;
    @Autowired
    private RekenMotorStrategyFactory rekenMotorStrategyFactory;
    @Autowired
    private LockLogService lockLogService;
    @Autowired
    private RekenenHelpService rekenenHelpService;
    @Autowired
    private WerkgeverService werkgeverService;
    @Autowired
    private CoreHrConfigurationService coreHrConfigurationService;

    private static final int REKENEN_ITEMNR = 9;

    private static final List<LockLogDTO> LOCKS = ImmutableList.of(new LockLogDTO(LockItemId.ALLPID, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLREKENAGENDA, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLWACHTAGENDA, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLMT, REKENEN_ITEMNR, LockType.EXCLUSIVE));

    @Override
    public MetaRekenFeedback start(Admin admin, String actor, RekenContext actionParams) {
        Collection<Integer> agendaIds = actionParams.getUnchecked(RekenActionParamKey.ARTIKEL_AGENDA_IDS_KEY);
        if (agendaIds != null) {
            return doeBerekeningenUitArtikelAgenda(admin, agendaIds, actor);
        } else {
            throw new MessageException("RekenUitAgendaService.run onvoldoende parameters");
        }
    }

    public MetaRekenFeedback doeBerekeningenUitArtikelAgenda(Admin admin, Collection<Integer> agendaIds, String actor) {
        Rekenmodus modus = Rekenmodus.VORM_ARTIKELS;
        MetaRekenFeedback metaFeedback = new MetaRekenFeedback(RekenActionType.REKEN_UIT_ARTIKELAGENDA, modus);
        List<LockLog> lockedItems = new ArrayList<>();
        try {
            lockedItems = lockLogService.lockItems(admin, LOCKS, actor);
            CacheContext.getInstance().clearCachedServices(Scope.ALL);
            log.trace("doeBerekeningenUitArtikelAgenda(adminId:{} ({});", admin.getId(), admin.getAdminDirTrimmed());

            TemporalContext.getInstance().setActualInterval(new Eternity());
            List<ArtikelAgenda> artikelAgendas;
            try {
                CriteriaBuilder cb = new CriteriaBuilder();
                cb.fetch("persoon{persoonSlices,opdrachten{opdrachtSlices}},werkgever{admin, werkgeverSlices}");
                cb.and("id", Criterium.IN(agendaIds));
                artikelAgendas = artikelAgendaService.findByCriteria(admin, cb);
            } finally {
                TemporalContext.getInstance().clearActualInterval();
            }
            List<Werkgever> werkgevers = werkgeverService.findByAdmin(admin, "");
            RekenmotorDtoConverter converter = new RekenmotorDtoConverter(werkgevers);
            List<ArtikelagendaDTO> artikelagendaDTOS = converter.convertArtikelagendas(artikelAgendas);
            checkInterupted();
            RekenAtoomInfo rekenAtoomInfo = bepaalRekenAtomen(admin, artikelAgendas);
            SetMultimap<RekenAtoom, Integer> rekenAtomenMap = rekenAtoomInfo.atomenToOpdrachtNrMap;
            metaFeedback.zetRekenAtomenEnArtikelAgenda(rekenAtomenMap, artikelagendaDTOS);
            schatAantalMaandOpdrachten(rekenAtomenMap.keySet());
            doeBerekeningenUitRekenAtomenNoCacheClear(admin, rekenAtoomInfo, modus, actor, metaFeedback);
        } finally {
            LockLogHelper lockLogHelper = new LockLogHelper(lockLogService, log);
            lockLogHelper.unlockItems(admin, lockedItems);
        }
        return metaFeedback;
    }

    private SetMultimap<RekenAtoom, LocalDateInterval> mergeIntervallen(SetMultimap<RekenAtoom, LocalDateInterval> input) {
        SetMultimap<RekenAtoom, LocalDateInterval> atomenToIntervalMap = HashMultimap.create();
        for (RekenAtoom rekenAtoom : input.keySet()) {
            Set<LocalDateInterval> merged = mergeIntervallen(input.get(rekenAtoom));
            atomenToIntervalMap.putAll(rekenAtoom, merged);
        }
        return atomenToIntervalMap;
    }

    private Set<LocalDateInterval> mergeIntervallen(Set<LocalDateInterval> input) {
        TreeSet<LocalDateInterval> sorted = new TreeSet<>(LocalDateIntervalComparator.DEFAULT);
        sorted.addAll(input);
        Set<LocalDateInterval> merged = new HashSet<>();
        LocalDateInterval current = null;
        for (LocalDateInterval interval : sorted) {
            if (current == null) {
                current = interval;
            } else if (interval.getStart().compareTo(current.getEnd()) <= 0) {
                LocalDate end = Ordering.natural().max(current.getEnd(), interval.getEnd());
                current = new LocalDateInterval(current.getStart(), end);
            } else {
                merged.add(current);
                current = interval;
            }
        }
        merged.add(current);
        return merged;
    }

    private static class RekenAtoomInfo {

        SetMultimap<RekenAtoom, Integer> atomenToOpdrachtNrMap;
        SetMultimap<RekenAtoom, LocalDateInterval> atomenToBoekIntervalMap;

        public RekenAtoomInfo(
                SetMultimap<RekenAtoom, Integer> atomenToOpdrachtNrMap,
                SetMultimap<RekenAtoom, LocalDateInterval> atomenToBoekIntervalMap) {
            this.atomenToOpdrachtNrMap = atomenToOpdrachtNrMap;
            this.atomenToBoekIntervalMap = atomenToBoekIntervalMap;
        }

        public SetMultimap<RekenAtoom, Integer> getAtomenToOpdrachtNrMap() {
            return atomenToOpdrachtNrMap;
        }

        public SetMultimap<RekenAtoom, LocalDateInterval> getAtomenToBoekIntervalMap() {
            return atomenToBoekIntervalMap;
        }
    }

    public RekenAtoomInfo bepaalRekenAtomen(Admin admin, List<ArtikelAgenda> artikelAgenda) {
        LocalDateTime rekenTijdstip = TemporalContext.getInstance().getWerkTijdstip();
        LocalDate rekenDatum = rekenTijdstip.toLocalDate();
        SetMultimap<RekenAtoom, Integer> atomenToOpdrachtNrMap = TreeMultimap.create();
        SetMultimap<RekenAtoom, LocalDateInterval> atomenToBoekIntervalMap = HashMultimap.create();
        for (ArtikelAgenda punt : artikelAgenda) {
            RekenAtoomInfo rekenAtoomInfo = bepaalRekenAtomen(admin, punt, rekenDatum, rekenTijdstip);
            atomenToOpdrachtNrMap.putAll(rekenAtoomInfo.getAtomenToOpdrachtNrMap());
            atomenToBoekIntervalMap.putAll(rekenAtoomInfo.getAtomenToBoekIntervalMap());
        }
        atomenToBoekIntervalMap = mergeIntervallen(atomenToBoekIntervalMap);
        return new RekenAtoomInfo(atomenToOpdrachtNrMap, atomenToBoekIntervalMap);
    }

    private RekenAtoomInfo bepaalRekenAtomen(Admin admin, ArtikelAgenda punt, LocalDate rekenDatum, LocalDateTime rekenTijdstip) {
        log.trace("bepaalRekenAtomen({});", LogTools.toSimpleLog(punt));
        SetMultimap<RekenAtoom, Integer> atomenToOpdrachtNrMap = TreeMultimap.create();
        SetMultimap<RekenAtoom, LocalDateInterval> atomenToBoekIntervalMap = HashMultimap.create();
        List<Opdracht> opdrachten = findOpdrachtenByArtikelAgenda(admin, punt);
        LocalDate beginDatum = punt.getBeginDatum().dayOfMonth().withMinimumValue();
        LocalDate eindDatum = punt.getEindDatum().dayOfMonth().withMaximumValue();
        LocalDate loopDatum = beginDatum;

        while (loopDatum.compareTo(eindDatum) <= 0) {
            for (Opdracht opdracht : opdrachten) {
                //TODO bespreken welke waarden deze moeten hebben
                LocalDate beslagDatum = rekenDatum;
                LocalDate boekDatum = rekenDatum;
                LocalDateInterval rekenPeriode = new Month(loopDatum);
                RekenTijd rekenTijd = new RekenTijd(rekenPeriode, rekenDatum, boekDatum, beslagDatum, rekenTijdstip);
                RekenAtoom atoom = new RekenAtoom(rekenTijd, opdracht.getPersoon().getId());
                atomenToOpdrachtNrMap.put(atoom, opdracht.getOpdrachtnr());
                atomenToBoekIntervalMap.put(atoom, punt.getBoekDatumInterval());
            }
            loopDatum = loopDatum.plusMonths(1);
        }
        return new RekenAtoomInfo(atomenToOpdrachtNrMap, atomenToBoekIntervalMap);
    }

    private void schatAantalMaandOpdrachten(Set<RekenAtoom> rekenAtomen) {
        if (!rekenAtomen.isEmpty()) {
            RekenProcesImp.setTotaalStatic(rekenAtomen.size());
        } else {
            log.trace("Lege berekening");
            RekenProcesImp.setTotaalStatic(1);
            RekenProcesImp.incrementVerwerktStatic();
        }
    }

    private void doeBerekeningenUitRekenAtomenNoCacheClear(Admin admin, RekenAtoomInfo rekenAtoomInfo, Rekenmodus modus, String actor, MetaRekenFeedback metaFeedback) {
        RekenMotorStrategy strategy = rekenMotorStrategyFactory.getVormArtikelStrategy(admin);
        RekenLogStatus status = RekenLogStatus.SUCCES;
        RekenContext rekenContext = new RekenContext();
        SetMultimap<RekenAtoom, Integer> rekenAtomenMap = rekenAtoomInfo.getAtomenToOpdrachtNrMap();
        SetMultimap<RekenAtoom, LocalDateInterval> boekIntervalMap = rekenAtoomInfo.getAtomenToBoekIntervalMap();
        CoreHrConfiguratie coreHrConfiguratie = coreHrConfigurationService.getCoreHrConfiguratie(admin);
        for (RekenAtoom atoom : rekenAtomenMap.keySet()) {
            Set<Integer> opdrachtNrs = rekenAtomenMap.get(atoom);
            Set<LocalDateInterval> boekIntervallen = boekIntervalMap.get(atoom);
            RekenContext actionParams = new RekenContext();
            actionParams.put(RekenChainKey.BOEK_DATUM_INTERVALLEN_SET_KEY, boekIntervallen);
            checkInterupted();
            try {
                rekenContext = vormArtikelsRekenmotorService
                        .berekenLoon(admin, atoom.getPersoonId(), opdrachtNrs, atoom.getRekenTijd(), strategy, modus, actor, actionParams, coreHrConfiguratie);
            } catch (Exception exception) {
                rekenenHelpService.logFatalException(admin, atoom.getRekenTijd().beginDatum, atoom.getPersoonId(), opdrachtNrs, exception);
                status = RekenLogStatus.FATAL_ERROR;
            }
            RekenFeedback rekenFeedback = metaFeedback.rekenFeedbackPerAtoom(atoom, rekenContext.getUnchecked(RekenChainKey.REKEN_FEEDBACK_KEY));
            RekenProcesImp.incrementVerwerktStatic();
            try {
                rekenenHelpService.doeRekenLog(admin, atoom.getPersoonId(), opdrachtNrs, atoom.getRekenTijd(), modus, status, rekenFeedback, actor);
            } catch (Exception exception) {
                log.debug("Logging failed", exception);
            }
        }
    }

    public List<Opdracht> findOpdrachtenByArtikelAgenda(Admin admin, ArtikelAgenda artikelAgenda) {
        return findOpdrachtenByArtikelAgenda(admin, artikelAgenda, null);
    }

    public List<Opdracht> findOpdrachtenByArtikelAgenda(Admin admin, ArtikelAgenda artikelAgenda, String fetchFields) {
        CriteriaBuilder cb = new CriteriaBuilder(fetchFields);
        cb.and("werkgever", Criterium.EQ(artikelAgenda.getWerkgever()));
        cb.and("persoon", Criterium.EQ(artikelAgenda.getPersoon()));
        cb.and("opdrachtnr", Criterium.EQ(artikelAgenda.getOpdrachtNummer()));
        TemporalContext temporalContext = TemporalContext.getInstance();
        temporalContext.setActualInterval(new LocalDateInterval(artikelAgenda.getBeginDatum(), artikelAgenda.getEindDatum()));
        List<Opdracht> opdrachten = opdrachtService.findByCriteria(admin, cb);
        temporalContext.clearActualInterval();
        return opdrachten;
    }

    private void checkInterupted() {
        if (RekenProcesImp.isInStopState()) {
            throw new ProcesHaltedException("Shall halt");
        }
    }

}
